import{_ as e,o as n,c as s,ae as t}from"./chunks/framework.CFyvOAXl.js";const p="/img/developmentEnv/javaInstall01.png",l="/img/developmentEnv/javaInstall02.png",r="/img/developmentEnv/javaInstall03.png",i="/img/developmentEnv/javaInstall04.png",o="/img/developmentEnv/javaInstall05.png",m="/img/developmentEnv/mvnInstall01.png",c="/img/developmentEnv/mvnInstall02.png",d="/img/developmentEnv/mvnInstall03.png",v="/img/developmentEnv/mvnInstall04.png",h="/img/developmentEnv/ideaSet01.png",g="/img/developmentEnv/ideaSet02.png",A=JSON.parse('{"title":"开发环境配置","description":"","frontmatter":{},"headers":[],"relativePath":"program/end/开发环境配置.md","filePath":"program/end/开发环境配置.md","lastUpdated":1777567730000}'),b={name:"program/end/开发环境配置.md"};function _(u,a,f,j,k,P){return n(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="开发环境配置" tabindex="-1">开发环境配置 <a class="header-anchor" href="#开发环境配置" aria-label="Permalink to &quot;开发环境配置&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#_1-jdk安装">1 jdk安装</a><ul><li><a href="#step1-下载jdk">step1 下载jdk</a></li><li><a href="#step2-配置环境变量">step2 配置环境变量</a></li><li><a href="#step3-检测是否安装成功">step3 检测是否安装成功</a></li></ul></li><li><a href="#_2-maven安装">2 maven安装</a><ul><li><a href="#step1-下载maven">step1 下载Maven</a></li><li><a href="#step2-配置环境变量-1">step2 配置环境变量</a></li><li><a href="#step3-检测是否安装成功-1">step3 检测是否安装成功</a></li><li><a href="#step4-配置本地maven仓库">step4 配置本地maven仓库</a></li></ul></li><li><a href="#_3-idea设置">3 IDEA设置</a></li></ul></nav><h2 id="_1-jdk安装" tabindex="-1">1 jdk安装 <a class="header-anchor" href="#_1-jdk安装" aria-label="Permalink to &quot;1 jdk安装&quot;">​</a></h2><h3 id="step1-下载jdk" tabindex="-1">step1 下载jdk <a class="header-anchor" href="#step1-下载jdk" aria-label="Permalink to &quot;step1 下载jdk&quot;">​</a></h3><p>JDK1.8 下载链接：<a href="https://www.oracle.com/java/technologies/javase/javase-jdk8-downloads.html" target="_blank" rel="noreferrer">https://www.oracle.com/java/technologies/javase/javase-jdk8-downloads.html</a></p><p>PC安装路径：D:\\Program Files\\Java\\jdk1.8.0_251\\</p><p>Java Platform Standard Edition 8 Documentation：<a href="https://docs.oracle.com/javase/8/docs/" target="_blank" rel="noreferrer">https://docs.oracle.com/javase/8/docs/</a></p><p><img src="'+p+'" alt="java-env-install-01"></p><p><img src="'+l+'" alt="java-env-install-02"></p><p><img src="'+r+'" alt="java-env-install-03"></p><h3 id="step2-配置环境变量" tabindex="-1">step2 配置环境变量 <a class="header-anchor" href="#step2-配置环境变量" aria-label="Permalink to &quot;step2 配置环境变量&quot;">​</a></h3><p>（1）变量配置</p><table tabindex="0"><thead><tr><th>变量名</th><th>变量值</th></tr></thead><tbody><tr><td>JAVA_HOME</td><td>D:\\Program Files\\Java\\jdk1.8.0_251</td></tr><tr><td>CLASSPATH</td><td>.;%JAVA_HOME%\\lib\\dt.jar;%JAVA_HOME%\\lib\\tools.jar;</td></tr><tr><td>Path</td><td>%JAVA_HOME%\\bin;%JAVA_HOME%\\jre\\bin;</td></tr></tbody></table><p><img src="'+i+'" alt="java-env-install-04"></p><h3 id="step3-检测是否安装成功" tabindex="-1">step3 检测是否安装成功 <a class="header-anchor" href="#step3-检测是否安装成功" aria-label="Permalink to &quot;step3 检测是否安装成功&quot;">​</a></h3><p><img src="'+o+'" alt="java-env-install-05"></p><h2 id="_2-maven安装" tabindex="-1">2 maven安装 <a class="header-anchor" href="#_2-maven安装" aria-label="Permalink to &quot;2 maven安装&quot;">​</a></h2><h3 id="step1-下载maven" tabindex="-1">step1 下载Maven <a class="header-anchor" href="#step1-下载maven" aria-label="Permalink to &quot;step1 下载Maven&quot;">​</a></h3><p>下载链接：<a href="https://maven.apache.org/download.cgi" target="_blank" rel="noreferrer">https://maven.apache.org/download.cgi</a></p><p><img src="'+m+'" alt="mvn-env-install-01"></p><p>解压目录：D:\\Program Files\\Apache\\apache-maven-3.6.3</p><h3 id="step2-配置环境变量-1" tabindex="-1">step2 配置环境变量 <a class="header-anchor" href="#step2-配置环境变量-1" aria-label="Permalink to &quot;step2 配置环境变量&quot;">​</a></h3><p>新建环境变量MAVEN_HOME，D:\\Program Files\\Apache\\apache-maven-3.6.3</p><p>编辑环境变量Path，追加%MAVEN_HOME%\\bin;</p><p><img src="'+c+'" alt="mvn-env-install-02"></p><h3 id="step3-检测是否安装成功-1" tabindex="-1">step3 检测是否安装成功 <a class="header-anchor" href="#step3-检测是否安装成功-1" aria-label="Permalink to &quot;step3 检测是否安装成功&quot;">​</a></h3><p>检测是否安装成功</p><p><img src="'+d+'" alt="mvn-env-install-03"></p><h3 id="step4-配置本地maven仓库" tabindex="-1">step4 配置本地maven仓库 <a class="header-anchor" href="#step4-配置本地maven仓库" aria-label="Permalink to &quot;step4 配置本地maven仓库&quot;">​</a></h3><p>（1）在D:\\Program Files\\Apache\\目录下新建maven-repository文件夹，该目录用作maven的本地库。</p><p>（2）打开D:\\Program Files\\Apache\\apache-maven-3.6.3\\conf\\settings.xml文件，查找下面这行代码：/path/to/local/repo</p><p>localRepository节点默认是被注释掉的，需要把它移到注释之外，然后将localRepository节点的值改为我们创建的目录D:\\Program Files\\Apache\\maven-repository。</p><p><img src="'+v+`" alt="mvn-env-install-04"></p><p>（3）localRepository节点用于配置本地仓库，本地仓库其实起到了一个缓存的作用，它的默认地址是 C:\\Users\\用户名.m2。</p><p>当我们从maven中获取jar包的时候，maven首先会在本地仓库中查找，如果本地仓库有则返回；如果没有则从远程仓库中获取包，并在本地库中保存。</p><p>（4）此外，我们在maven项目中运行mvn install，项目将会自动打包并安装到本地仓库中。</p><p>mvn help:system</p><p>如果前面的配置成功，那么D:\\Program Files\\Apache\\maven-repository会出现一些文件。</p><p>(5)mvn的settings.xml的profiles部分需要添加</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>	&lt;profile&gt;</span></span>
<span class="line"><span>      &lt;id&gt;jdk-1.8&lt;/id&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>      &lt;activation&gt;</span></span>
<span class="line"><span>	    &lt;activeByDefault&gt;true&lt;/activeByDefault&gt;</span></span>
<span class="line"><span>        &lt;jdk&gt;1.8&lt;/jdk&gt;</span></span>
<span class="line"><span>      &lt;/activation&gt;</span></span>
<span class="line"><span>	  </span></span>
<span class="line"><span>	  &lt;properties&gt;</span></span>
<span class="line"><span>		&lt;maven.compiler.source&gt;1.8&lt;/maven.compiler.source&gt;</span></span>
<span class="line"><span>		&lt;maven.compiler.target&gt;1.8&lt;/maven.compiler.target&gt;</span></span>
<span class="line"><span>		&lt;maven.compiler.compilerVersion&gt;1.8&lt;/maven.compiler.compilerVersion&gt;</span></span>
<span class="line"><span>	  &lt;/properties&gt;</span></span>
<span class="line"><span>    &lt;/profile&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h2 id="_3-idea设置" tabindex="-1">3 IDEA设置 <a class="header-anchor" href="#_3-idea设置" aria-label="Permalink to &quot;3 IDEA设置&quot;">​</a></h2><p>step1 Configure中选择Settings</p><p><img src="`+h+'" alt="idea-set-01"></p><p>step2 配置mvn目录、设置文件、本地仓库。</p><p>Build，Execution，Deployment &gt;&gt; Build Tools &gt;&gt; Maven &gt;&gt;</p><p><img src="'+g+'" alt="idea-set-02"></p><p>注：最后修改日期：2020/07/05</p>',47)])])}const q=e(b,[["render",_]]);export{A as __pageData,q as default};
